#include <iostream>
#include <chrono>
using namespace std;

class Game {
private:
    bool running;
    float deltaTime;

public:
    Game() : running(true), deltaTime(0.0f) {}

    void handleInput() {
        // Обработка нажатий клавиш
        cout << "Input handled" << endl;
    }

    void update(float dt) {
        // Обновление логики игры
        cout << "Game updated, dt: " << dt << endl;
    }

    void render() {
        // Рисование кадра
        cout << "Frame rendered" << endl;
    }

    void run() {
        auto lastTime = chrono::high_resolution_clock::now();

        while (running) {
            auto currentTime = chrono::high_resolution_clock::now();
            deltaTime = chrono::duration<float>(currentTime - lastTime).count();
            lastTime = currentTime;

            handleInput();
            update(deltaTime);
            render();

            if (deltaTime > 1.0f) running = false;  // Завершить через 1 секунду
        }
    }
};

int main() {
    Game game;
    game.run();
    return 0;
}

#include <iostream>
#include <cmath>
using namespace std;

class PhysicsObject {
public:
    float x, y;           // позиция
    float vx, vy;         // скорость
    float ax, ay;         // ускорение
    float mass;           // масса

    PhysicsObject(float x_, float y_, float mass_)
        : x(x_), y(y_), vx(0), vy(0), ax(0), ay(0), mass(mass_) {}

    void applyForce(float fx, float fy) {
        ax = fx / mass;   // a = F / m
        ay = fy / mass;
    }

    void update(float dt) {
        // Обновляем скорость
        vx += ax * dt;
        vy += ay * dt;

        // Обновляем позицию
        x += vx * dt;
        y += vy * dt;

        // Гравитация
        ay = 9.8f;  // вниз
    }

    float getSpeed() const {
        return sqrt(vx * vx + vy * vy);
    }
};

int main() {
    PhysicsObject ball(100, 100, 1.0f);

    // Прыжок (начальная скорость вверх)
    ball.vy = -10;  // отрицательная = вверх

    for (int i = 0; i < 100; i++) {
        ball.update(0.016f);  // 60 FPS
        cout << "y: " << ball.y << " vy: " << ball.vy << endl;

        if (ball.y >= 100) break;  // Упал на землю
    }

    return 0;
}

